import{_ as e,o as a,c as r,a4 as d}from"./chunks/framework.BybBnFXO.js";const m=JSON.parse('{"title":"色心致色","description":"","frontmatter":{"title":"色心致色","colorCause":"color-centers"},"headers":[],"relativePath":"zh/color-causes/color-centers.md","filePath":"zh/color-causes/color-centers.md","lastUpdated":1784176423000}'),o={name:"zh/color-causes/color-centers.md"};function l(n,t,i,c,s,h){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="色心致色" tabindex="-1">色心致色 <a class="header-anchor" href="#色心致色" aria-label="Permalink to &quot;色心致色&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>色心是晶格中能选择性吸收可见光的点缺陷。当晶格缺少某个离子 （空位）、多出一个离子（间隙），或含有杂质离子改变局部电荷平衡 时，邻近的电子或空穴被束缚在缺陷处形成&quot;色心&quot;，其能级刚好落在 可见光波段。色心可通过天然辐射或人工辐照（如加热后辐照）产生， 也可能因日晒褪色，这是检测优化处理的关键判断点。</p><h2 id="致色机制" tabindex="-1">致色机制 <a class="header-anchor" href="#致色机制" aria-label="Permalink to &quot;致色机制&quot;">​</a></h2><p>常见色心类型：</p><ul><li><strong>F 心</strong>（阴离子空位捕获电子）：常见于萤石、紫色石盐</li><li><strong>V 心</strong>（阳离子空位捕获空穴）：紫色石英（紫晶）</li><li><strong>杂质色心</strong>：杂质离子周围电子空位，如紫晶的 Fe⁴⁺ 色心 色心可在实验室通过辐照加速形成，但天然色心通常经过数百万年辐 射积累。辐照处理宝石的检测常依赖色心在短波紫外下的发光特征。</li></ul><h2 id="示例宝石" tabindex="-1">示例宝石 <a class="header-anchor" href="#示例宝石" aria-label="Permalink to &quot;示例宝石&quot;">​</a></h2><table tabindex="0"><thead><tr><th>宝石</th><th>缺陷类型</th><th>化学式宿主</th><th>颜色</th></tr></thead><tbody><tr><td>Amethyst / 紫晶</td><td>Fe⁴⁺ color center</td><td>SiO₂</td><td>violet</td></tr><tr><td>Smoky Quartz / 烟晶</td><td>Al impurity + e⁻</td><td>SiO₂</td><td>brown</td></tr><tr><td>Citrine / 黄水晶</td><td>Fe³⁺ color center</td><td>SiO₂</td><td>yellow</td></tr><tr><td>Fluorite / 萤石</td><td>F-center (vacancy)</td><td>CaF₂</td><td>purple / blue</td></tr><tr><td>Yellow Diamond / 黄钻</td><td>N + vacancy (H3)</td><td>C (diamond)</td><td>yellow</td></tr><tr><td>Pink Diamond / 粉钻</td><td>N + plastic deformation</td><td>C (diamond)</td><td>pink</td></tr></tbody></table><p><em>详见<a href="./intro.html">颜色成因总览</a>。</em></p>',9)])])}const p=e(o,[["render",l]]);export{m as __pageData,p as default};
